#include <iostream>
#include <vector>
int largestIndex(const std::vector<int>& v){
 if(v.empty()) return -1;
 std::size_t best=0;
 for(std::size_t i=1;i<v.size();i++) if(v[i]>v[best]) best=i;
 return static_cast<int>(best);
}
int main(){std::cout<<largestIndex({4,9,7})<<"\n";}
